mapper.select:
SELECT #{query.statDate} AS stat_date,
       #{query.clinicId} AS clinic_id,


               (SELECT clinic_name FROM clinic WHERE id = #{query.clinicId} LIMIT 1) AS clinic_name,


               '全部门诊' AS clinic_name,


       COALESCE((
           SELECT COUNT(1)
           FROM appointment a
           WHERE a.org_id = #{orgId}
             AND a.is_deleted = 0
             AND a.appointment_date = #{query.statDate}

                 AND a.clinic_id = #{query.clinicId}

       ), 0) AS appointment_count,
       COALESCE((
           SELECT COUNT(1)
           FROM appointment a
           WHERE a.org_id = #{orgId}
             AND a.is_deleted = 0
             AND a.appointment_date = #{query.statDate}
             AND a.status = 'ARRIVED'

                 AND a.clinic_id = #{query.clinicId}

       ), 0) AS arrived_count,
       COALESCE((
           SELECT COUNT(1)
           FROM appointment a
           WHERE a.org_id = #{orgId}
             AND a.is_deleted = 0
             AND a.appointment_date = #{query.statDate}
             AND a.appointment_type = 'FIRST'

                 AND a.clinic_id = #{query.clinicId}

       ), 0) AS first_visit_count,
       COALESCE((
           SELECT COUNT(1)
           FROM appointment a
           WHERE a.org_id = #{orgId}
             AND a.is_deleted = 0
             AND a.appointment_date = #{query.statDate}
             AND a.appointment_type = 'REVISIT'

                 AND a.clinic_id = #{query.clinicId}

       ), 0) AS revisit_count,
       COALESCE((
           SELECT COUNT(1)
           FROM charge_order co
           WHERE co.org_id = #{orgId}
             AND co.is_deleted = 0
             AND DATE(co.charge_time) = #{query.statDate}

                 AND co.clinic_id = #{query.clinicId}

       ), 0) AS charge_order_count,
       COALESCE((
           SELECT SUM(co.receivable_amount)
           FROM charge_order co
           WHERE co.org_id = #{orgId}
             AND co.is_deleted = 0
             AND DATE(co.charge_time) = #{query.statDate}

                 AND co.clinic_id = #{query.clinicId}

       ), 0.00) AS receivable_amount,
       COALESCE((
           SELECT SUM(co.paid_amount)
           FROM charge_order co
           WHERE co.org_id = #{orgId}
             AND co.is_deleted = 0
             AND DATE(co.charge_time) = #{query.statDate}

                 AND co.clinic_id = #{query.clinicId}

       ), 0.00) AS paid_amount,
       COALESCE((
           SELECT SUM(rr.refund_amount)
           FROM refund_record rr
           WHERE rr.org_id = #{orgId}
             AND rr.refund_status = 'SUCCESS'
             AND DATE(rr.refunded_at) = #{query.statDate}

                 AND rr.clinic_id = #{query.clinicId}

       ), 0.00) AS refund_amount,
       COALESCE((
           SELECT SUM(co.arrears_amount)
           FROM charge_order co
           WHERE co.org_id = #{orgId}
             AND co.is_deleted = 0
             AND DATE(co.charge_time) = #{query.statDate}

                 AND co.clinic_id = #{query.clinicId}

       ), 0.00) AS arrears_amount

SELECT #{query.statDate} AS statDate,
       s.main_clinic_id AS clinicId,
       c.clinic_name AS clinicName,
       s.id AS doctorId,
       s.staff_name AS doctorName,
       COALESCE((
           SELECT COUNT(1)
           FROM appointment a
           WHERE a.org_id = #{orgId}
             AND a.is_deleted = 0
             AND a.doctor_id = s.id
             AND a.appointment_date = #{query.statDate}

                 AND a.clinic_id = #{query.clinicId}

       ), 0) AS appointmentCount,
       COALESCE((
           SELECT COUNT(1)
           FROM appointment a
           WHERE a.org_id = #{orgId}
             AND a.is_deleted = 0
             AND a.doctor_id = s.id
             AND a.status = 'ARRIVED'
             AND a.appointment_date = #{query.statDate}

                 AND a.clinic_id = #{query.clinicId}

       ), 0) AS arrivedCount,
       COALESCE((
           SELECT COUNT(1)
           FROM appointment a
           WHERE a.org_id = #{orgId}
             AND a.is_deleted = 0
             AND a.doctor_id = s.id
             AND a.appointment_type = 'FIRST'
             AND a.appointment_date = #{query.statDate}

                 AND a.clinic_id = #{query.clinicId}

       ), 0) AS firstVisitCount,
       COALESCE((
           SELECT COUNT(1)
           FROM appointment a
           WHERE a.org_id = #{orgId}
             AND a.is_deleted = 0
             AND a.doctor_id = s.id
             AND a.appointment_type = 'REVISIT'
             AND a.appointment_date = #{query.statDate}

                 AND a.clinic_id = #{query.clinicId}

       ), 0) AS revisitCount,
       COALESCE((
           SELECT COUNT(1)
           FROM medical_record mr
           WHERE mr.org_id = #{orgId}
             AND mr.is_deleted = 0
             AND mr.doctor_id = s.id
             AND DATE(mr.visit_date) = #{query.statDate}

                 AND mr.clinic_id = #{query.clinicId}

       ), 0) AS treatmentCount,
       COALESCE((
           SELECT SUM(ci.receivable_amount)
           FROM charge_item ci
           JOIN charge_order co ON co.id = ci.charge_order_id
           WHERE co.org_id = #{orgId}
             AND co.is_deleted = 0
             AND ci.doctor_id = s.id
             AND DATE(co.charge_time) = #{query.statDate}

                 AND co.clinic_id = #{query.clinicId}

       ), 0.00) AS performanceAmount
FROM staff s
LEFT JOIN clinic c ON c.id = s.main_clinic_id
WHERE s.org_id = #{orgId}
  AND s.is_deleted = 0
  AND s.status = 1
  AND s.is_doctor = 1

    AND s.id = #{query.doctorId}


    AND s.main_clinic_id = #{query.clinicId}


    AND s.main_clinic_id IN

        #{clinicId}


ORDER BY performanceAmount DESC, doctorId ASC
